insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('pmi-jun', '1 Jul 2026', 'Absa / S&P Global PMI', 'headwind', 'Factory activity stalls — production back in contraction', 'The manufacturing PMI eased to 50.8 (from 52.6), but the production sub-index tumbled to 43.5 and new orders to 44.6: demand pulled forward in April faded and a softer rand raised input costs.', '["new orders ↓","output contracts","manufacturing drags GDP","factory jobs at risk"]'::jsonb, 'Manufacturing stays the recovery''s weak link — the sector that fell 0.8% in Q1 GDP still can''t find momentum even as fuel relief lands.', '["Manufacturing","GDP","Jobs"]'::jsonb, 'manuf', -1, 'Trace the factory slump', '[{"theme":"Manufacturers & industrial jobs","dir":"down","note":"Contracting output puts factory employment under pressure."},{"theme":"Steel, chemicals, auto suppliers","dir":"down","note":"Weak orders ripple up the industrial supply chain."},{"theme":"Importers of finished goods","dir":"up","note":"Local weakness leaves room for imported substitutes."},{"theme":"Rate-cut case","dir":"up","note":"Soft activity strengthens the argument for eventual easing."}]'::jsonb, 10) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('ceasefire-oil', 'late Jun 2026', 'Markets / energy wires', 'tailwind', 'US–Iran MOU collapses Brent''s monthly average from ~$105 to ~$87', 'The Strait of Hormuz risk premium that drove oil above $100 unwound after the US–Iran memorandum. The rand firmed from ~R16.65 to an average ~R16.37/$ as the import-bill outlook improved; spot Brent fell toward ~$75.', '["Brent −$29","basic fuel price ↓","transport CPI cools","inflation expectations ease","pressure off SARB"]'::jsonb, 'Biggest single disinflation impulse of the year. If it holds, the July CPI print (due Aug) turns the corner.', '["CPI","Rand","Repo"]'::jsonb, 'oil', -1, 'Trace oil''s collapse', '[{"theme":"Transport & logistics","dir":"up","note":"Cheaper diesel cuts freight, taxi and delivery costs."},{"theme":"Consumers & retail","dir":"up","note":"Lower pump prices free up household income to spend."},{"theme":"Fuel-levy revenue","dir":"down","note":"Government''s fuel take softens as prices fall."},{"theme":"Rand-hedge exposure","dir":"down","note":"A firmer rand reduces the value of offshore hedges."}]'::jsonb, 9) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('july-fuel', '1 Jul 2026 · in effect', 'DMRE fuel adjustment', 'tailwind', 'July fuel cut now in effect: petrol −R2.01/l, diesel −R3.59/l', 'Live from 1 July: 93-octane petrol −R2.01, 95-octane −R1.96, diesel −R3.14 to −R3.59, paraffin −R5.23. The oil collapse and a firmer rand (avg R16.37/$) passed straight through to the pump.', '["pump price ↓","household real income ↑","freight & food logistics costs ↓","food CPI relief with a lag"]'::jsonb, 'Direct relief to the exact categories (transport 9.4%, food) that drove the May CPI spike to 4.5%.', '["CPI","Consumption","Sectors"]'::jsonb, 'fuel', -1, 'Trace the fuel cut', '[{"theme":"Freight & food logistics","dir":"up","note":"Diesel down R3.59/l lowers the cost of moving everything."},{"theme":"Household budgets","dir":"up","note":"The biggest pump cut in years restores real income."},{"theme":"Inflation-linked assets","dir":"down","note":"Cooling CPI erodes the inflation premium."}]'::jsonb, 8) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('mpc-july', 'due 23 Jul 2026', 'SARB MPC', 'watch', 'MPC decision: hold now favoured after the oil crash', 'May''s 25bps hike to 7.00% was a pre-emptive strike at the oil shock. With Brent at ~$75 and the rand firmer, the hike case has faded — but SARB flagged services inflation at 4.6% and non-fuel pressures (insurance, financial services).', '["June CPI print 22 Jul","MPC reads it next morning","hold = relief for borrowers","surprise hike = rand support, growth drag"]'::jsonb, 'The first big test of the new 3% target''s credibility in a shock. Watch the vote split — May''s was 4–2.', '["Repo","Rand","CPI"]'::jsonb, 'repo', 1, 'Trace a rate hike', '[{"theme":"Borrowers & mortgages","dir":"down","note":"A hike lifts repayments and squeezes disposable income."},{"theme":"Banks'' endowment margins","dir":"up","note":"Higher rates widen the spread earned on deposits."},{"theme":"The rand","dir":"up","note":"A wider rate gap attracts yield-seeking (carry) inflows."},{"theme":"Rate-sensitive retail & property","dir":"down","note":"Big-ticket, credit-driven demand cools."}]'::jsonb, 7) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('qlfs-q1', '12 May 2026', 'Stats SA QLFS', 'headwind', '345,000 jobs lost in Q1 — unemployment 32.7%', 'The worst quarterly jobs print in years: unemployment up 1.3pp, youth at 45.8%, and only KwaZulu-Natal added jobs. 8.1m people now want work the economy isn''t creating.', '["employment ↓","household income & spending ↓","consumption (60% of GDP) weakens","social strain & fiscal pressure ↑"]'::jsonb, 'Confirms the core thesis: 1–2% growth cannot absorb ~360k new entrants a year. The speed limit is the jobs crisis.', '["Labour","Consumption","Potential"]'::jsonb, 'jobs', -1, 'Trace the job losses', '[{"theme":"Consumer-facing sectors","dir":"down","note":"Fewer earners means weaker retail and services demand."},{"theme":"The social-grant bill","dir":"down","note":"Rising joblessness adds fiscal pressure."},{"theme":"Defensive staples","dir":"up","note":"Spending concentrates on essentials in a squeeze."}]'::jsonb, 6) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('gdp-q1', '3 Jun 2026', 'Stats SA GDP', 'watch', 'GDP grows +0.5% q/q — sixth straight quarter of expansion', 'Growth accelerated to +1.9% y/y, beating forecasts. Finance led, agriculture bounced (+3.9%) — but manufacturing fell 0.8% and fixed investment dropped another 1.1%.', '["momentum ↑","but investment ↓","capacity (potential) stays capped","recovery quality in question"]'::jsonb, 'Direction is right, composition is wrong: consumption-led upticks fade; investment-led ones compound. Watch GFCF.', '["GDP","Investment","Sectors"]'::jsonb, 'gdp', 1, 'Trace the growth print', '[{"theme":"Cyclical sectors (finance, trade)","dir":"up","note":"They lead a broadening recovery."},{"theme":"Tax revenue","dir":"up","note":"A bigger economy widens the fiscal take."},{"theme":"Manufacturing","dir":"down","note":"Still contracting despite the headline — the weak link."}]'::jsonb, 5) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('budget-debt', '25 Feb 2026', 'National Treasury 2026 Budget', 'tailwind', 'Debt stabilises at 78.9% of GDP — first time in 17 years', 'Gross loan debt peaks in 2025/26 and declines to 76.5% by 2028/29. Debt-service cost growth slows to ~3.7%/yr from 7.4% on improved market confidence and cheaper borrowing.', '["borrowing costs ↓","debt-service growth slows","fiscal space opens slowly","sovereign risk premium compresses"]'::jsonb, 'The quiet macro win underneath everything: every basis point saved on the R6.1tn debt stock is money for investment.', '["Fiscal","Debt","Rates"]'::jsonb, 'debt', -1, 'Trace debt stabilising', '[{"theme":"SA government bonds","dir":"up","note":"A stabilising debt path compresses the risk premium."},{"theme":"The rand & sovereign rating","dir":"up","note":"Fiscal credibility supports the currency and outlook."},{"theme":"Banks & insurers","dir":"up","note":"Large domestic bondholders gain from firmer prices."}]'::jsonb, 4) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('eskom-tariff', 'ongoing 2026', 'NERSA / Eskom', 'headwind', 'Electricity tariff hikes keep utilities inflation at 5.3%', 'Administered prices — electricity, water, municipal rates — keep rising well above the 3% target even as market-driven prices cool.', '["tariffs ↑","housing & utilities CPI 5.3%","sticky core pressure","SARB stays hawkish longer"]'::jsonb, 'The structural inflation problem no repo rate can fix — administered prices are a supply-side, governance problem.', '["CPI","Energy","Structural"]'::jsonb, 'energy', 1, 'Trace the tariff shock', '[{"theme":"Energy-intensive industry","dir":"down","note":"Above-inflation tariffs raise the cost base."},{"theme":"Solar & alternative energy","dir":"up","note":"Grid pain accelerates rooftop and private-generation adoption."},{"theme":"Households","dir":"down","note":"Administered prices keep utilities inflation elevated."}]'::jsonb, 3) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('rail-reform', 'ongoing 2026', 'Transnet / Op. Vulindlela', 'tailwind', 'Private rail operators start moving freight on Transnet''s network', 'Eleven private operators awarded slots as third-party access to the freight network becomes real; port concessions grind through litigation.', '["rail tonnage ↑","mining & manufacturing exports unlock","logistics constraint eases","potential growth ↑"]'::jsonb, 'One of the two reforms (with energy) that most directly raises the speed limit — the Diagnosis tab''s +0.4pp in motion.', '["Structural","Exports","Potential"]'::jsonb, 'logistics', -1, 'Trace the rail reform', '[{"theme":"Bulk miners & exporters","dir":"up","note":"Restored rail capacity unlocks stranded export volumes."},{"theme":"Private rail operators","dir":"up","note":"Third-party access is a new market opening up."},{"theme":"Road freight (trucking)","dir":"down","note":"Volumes shift back to rail as it recovers."}]'::jsonb, 2) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.news (id, date_label, source, tone, title, what, why, impact, tags, graph_origin, graph_dir, graph_verb, implications, sort) values ('water-gauteng', 'ongoing 2026', 'DWS / municipalities', 'headwind', 'Gauteng water stress becomes an investment risk', 'Leaks, pump failures and demand growth strain the Vaal system supplying the country''s economic hub; intermittent outages spread across Johannesburg and Tshwane.', '["water reliability ↓","operating costs ↑","new-investment deterrent in the 33%-of-GDP province","emerging binding constraint"]'::jsonb, 'The next load-shedding if unaddressed — the Diagnosis tab''s water constraint moving from ''emerging'' to ''binding''.', '["Structural","Water","Investment"]'::jsonb, 'water', 1, 'Trace the water risk', '[{"theme":"Gauteng property & new investment","dir":"down","note":"Water insecurity deters investment in the economic hub."},{"theme":"Water infrastructure & services","dir":"up","note":"Demand rises for fixes, storage and treatment."},{"theme":"Bottled water & tankering","dir":"up","note":"Households and firms buy around the shortfall."}]'::jsonb, 1) on conflict (id) do update set date_label=excluded.date_label, source=excluded.source, tone=excluded.tone, title=excluded.title, what=excluded.what, why=excluded.why, impact=excluded.impact, tags=excluded.tags, graph_origin=excluded.graph_origin, graph_dir=excluded.graph_dir, graph_verb=excluded.graph_verb, implications=excluded.implications, sort=excluded.sort;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('prod-may', 'Mining & manufacturing production', 'Stats SA', '2026-07-14', 'May 2026', '−0.8% m/m', '≈ flat', 'manuf', 'med', 'Manufacturing has been the drag on the recovery — a rebound would change the tone.', '{"label":"Stronger","dir":1,"note":"A production rebound lifts manufacturing and GDP."}'::jsonb, '{"label":"Weaker","dir":-1,"note":"Further contraction confirms the factory slump."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('cpi-jun', 'CPI inflation', 'Stats SA', '2026-07-22', 'June 2026', '4.5%', '≈ 4.4%', 'cpi', 'high', 'June still carries the petrol hike; the July fuel cut only shows up in next month''s print.', '{"label":"Hotter","dir":1,"note":"An upside surprise revives the hawkish rate case."}'::jsonb, '{"label":"Cooler","dir":-1,"note":"Disinflation resumes — room for an easier SARB."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('mpc-jul', 'SARB MPC rate decision', 'SARB', '2026-07-23', 'July 2026', '7.00%', 'hold 7.00%', 'repo', 'high', 'Oil''s collapse killed the hike case, but services inflation at 4.6% keeps the tone hawkish.', '{"label":"Surprise hike","dir":1,"note":"Tighter policy: firmer rand, weaker demand."}'::jsonb, '{"label":"Surprise cut","dir":-1,"note":"Easier policy: relief for borrowers and growth."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('trade-jun', 'Trade balance', 'SARS', '2026-07-31', 'June 2026', 'R +24bn', 'R +20bn', 'X', 'med', 'Gold and PGM prices are doing the heavy lifting on the export side.', '{"label":"Bigger surplus","dir":1,"note":"Strong exports support the rand and current account."}'::jsonb, '{"label":"Smaller / deficit","dir":-1,"note":"Weaker trade pressures the external balance."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('pmi-jul', 'Manufacturing PMI', 'Absa / BER', '2026-08-01', 'July 2026', '50.8', '≈ 50', 'manuf', 'med', 'The production sub-index at 43.5 is the real concern beneath the headline.', '{"label":"Expansion","dir":1,"note":"Above 50 signals factory orders recovering."}'::jsonb, '{"label":"Contraction","dir":-1,"note":"Below 50 deepens the manufacturing worry."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('qlfs-q2', 'Unemployment (QLFS)', 'Stats SA', '2026-08-12', 'Q2 2026', '32.7%', '≈ 32.4%', 'unemp', 'high', 'Q1 lost 345k jobs; Q2 is seasonally kinder, so a smaller rise is expected.', '{"label":"Higher jobless","dir":1,"note":"A worse print deepens the demand and fiscal strain."}'::jsonb, '{"label":"Lower jobless","dir":-1,"note":"Seasonal re-hiring pulls the rate back down."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('gdp-q2', 'GDP growth', 'Stats SA', '2026-09-08', 'Q2 2026', '+0.5% q/q', '≈ +0.4%', 'gdp', 'high', 'Composition matters more than the headline — watch whether fixed investment turns.', '{"label":"Stronger","dir":1,"note":"Momentum builds toward the 3% target."}'::jsonb, '{"label":"Weaker","dir":-1,"note":"The recovery stalls; investment still the missing piece."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
insert into public.releases (id, name, agency, release_at, period, previous, consensus, node, importance, watch, hi, lo) values ('mtbps', 'Medium-Term Budget (MTBPS)', 'National Treasury', '2026-10-29', '2026', 'debt 78.9%', 'stay the course', 'debt', 'high', 'The market wants proof the first debt stabilisation in 17 years actually holds.', '{"label":"Debt slips","dir":1,"note":"Fiscal slippage lifts the risk premium and pressures the rand."}'::jsonb, '{"label":"On track","dir":-1,"note":"Consolidation holding supports bonds and the rand."}'::jsonb) on conflict (id) do update set name=excluded.name, agency=excluded.agency, release_at=excluded.release_at, period=excluded.period, previous=excluded.previous, consensus=excluded.consensus, node=excluded.node, importance=excluded.importance, watch=excluded.watch, hi=excluded.hi, lo=excluded.lo;
